  `merchant_id` bigint NOT NULL COMMENT '商户ID',
  `cert_type` enum('BUSINESS_LICENSE','ID_CARD','OTHER') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '证件类型',
