-- ----------------------------
-- Table structure for properties
-- ----------------------------
DROP TABLE IF EXISTS `properties`;
CREATE TABLE `properties`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `merchant_id` bigint NOT NULL COMMENT '商户ID',
  `property_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '民宿名称',
  `property_type` enum('HOMESTAY','HOTEL','APARTMENT','VILLA','OTHER') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'HOMESTAY' COMMENT '类型：民宿/酒店/公寓/别墅/其他',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '描述',
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '详细地址',
  `province` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '省份',
  `city` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '城市',
  `district` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '区县',
  `longitude` decimal(10, 7) NULL DEFAULT NULL COMMENT '经度',
  `latitude` decimal(10, 7) NULL DEFAULT NULL COMMENT '纬度',
  `check_in_time` time NULL DEFAULT '14:00:00' COMMENT '入住时间',
  `check_out_time` time NULL DEFAULT '12:00:00' COMMENT '退房时间',
  `total_rooms` int NULL DEFAULT 0 COMMENT '总房间数',
  `available_rooms` int NULL DEFAULT 0 COMMENT '可用房间数',
  `rating` decimal(3, 2) NULL DEFAULT 0.00 COMMENT '评分（0-5）',
  `total_reviews` int NULL DEFAULT 0 COMMENT '总评价数',
  `price_range_min` decimal(10, 2) NULL DEFAULT NULL COMMENT '最低价格',
  `price_range_max` decimal(10, 2) NULL DEFAULT NULL COMMENT '最高价格',
  `facilities` json NULL COMMENT '设施列表（JSON：WiFi、停车场、早餐等）',
  `images` json NULL COMMENT '图片列表（JSON：封面图、详情图等）',
  `policies` json NULL COMMENT '政策说明（JSON：取消政策、宠物政策等）',
  `status` enum('DRAFT','PENDING','APPROVED','REJECTED','SUSPENDED') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'DRAFT' COMMENT '状态：草稿/待审核/已通过/已拒绝/已暂停',
  `is_featured` tinyint(1) NULL DEFAULT 0 COMMENT '是否推荐',
  `view_count` int NULL DEFAULT 0 COMMENT '浏览次数',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_merchant_id`(`merchant_id` ASC) USING BTREE,
  INDEX `idx_city`(`city` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_rating`(`rating` ASC) USING BTREE,
  INDEX `idx_location`(`longitude` ASC, `latitude` ASC) USING BTREE,
  CONSTRAINT `properties_ibfk_1` FOREIGN KEY (`merchant_id`) REFERENCES `merchants` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 606 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '民宿/酒店表' ROW_FORMAT = Dynamic;

